PRAGMA foreign_keys = OFF;
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:13', 91, 13, 30, 595, 6056, 'فَقَالَ لَهُمْ رَسُوْلُ اللّٰهِ نَاقَةَ اللّٰهِ وَسُقْيٰهَاۗ', 'Rasul Allah (Saleh) lalu berkata kepada mereka, “(Biarkanlah) unta betina Allah ini beserta minumannya.”', '', 'https://everyayah.com/data/Alafasy_128kbps/091013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:14', 91, 14, 30, 595, 6057, 'فَكَذَّبُوْهُ فَعَقَرُوْهَاۖ فَدَمْدَمَ عَلَيْهِمْ رَبُّهُمْ بِذَنْۢبِهِمْ فَسَوّٰىهَاۖ', 'Namun, mereka kemudian mendustakannya (Saleh) dan menyembelih (unta betina) itu. Maka, Tuhan membinasakan mereka karena dosa-dosanya, lalu meratakan mereka (dengan tanah).', '', 'https://everyayah.com/data/Alafasy_128kbps/091014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('91:15', 91, 15, 30, 595, 6058, 'وَلَا يَخَافُ عُقْبٰهَا ࣖ', 'Dia tidak takut terhadap akibatnya.', '', 'https://everyayah.com/data/Alafasy_128kbps/091015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:1', 92, 1, 30, 595, 6059, 'وَالَّيْلِ اِذَا يَغْشٰىۙ', 'Demi malam apabila menutupi (cahaya siang),', '', 'https://everyayah.com/data/Alafasy_128kbps/092001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:2', 92, 2, 30, 595, 6060, 'وَالنَّهَارِ اِذَا تَجَلّٰىۙ', 'demi siang apabila terang benderang,', '', 'https://everyayah.com/data/Alafasy_128kbps/092002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:3', 92, 3, 30, 595, 6061, 'وَمَا خَلَقَ الذَّكَرَ وَالْاُنْثٰىٓ ۙ', 'dan demi penciptaan laki-laki dan perempuan,', '', 'https://everyayah.com/data/Alafasy_128kbps/092003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:4', 92, 4, 30, 595, 6062, 'اِنَّ سَعْيَكُمْ لَشَتّٰىۗ', 'sesungguhnya usahamu benar-benar beraneka ragam.', '', 'https://everyayah.com/data/Alafasy_128kbps/092004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:5', 92, 5, 30, 595, 6063, 'فَاَمَّا مَنْ اَعْطٰى وَاتَّقٰىۙ', 'Siapa yang memberikan (hartanya di jalan Allah) dan bertakwa', '', 'https://everyayah.com/data/Alafasy_128kbps/092005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:6', 92, 6, 30, 595, 6064, 'وَصَدَّقَ بِالْحُسْنٰىۙ', 'serta membenarkan adanya (balasan) yang terbaik (surga),', '', 'https://everyayah.com/data/Alafasy_128kbps/092006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:7', 92, 7, 30, 595, 6065, 'فَسَنُيَسِّرُهٗ لِلْيُسْرٰىۗ', 'Kami akan melapangkan baginya jalan kemudahan (kebahagiaan).', '', 'https://everyayah.com/data/Alafasy_128kbps/092007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:8', 92, 8, 30, 595, 6066, 'وَاَمَّا مَنْۢ بَخِلَ وَاسْتَغْنٰىۙ', 'Adapun orang yang kikir dan merasa dirinya cukup (tidak perlu pertolongan Allah)', '', 'https://everyayah.com/data/Alafasy_128kbps/092008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:9', 92, 9, 30, 595, 6067, 'وَكَذَّبَ بِالْحُسْنٰىۙ', 'serta mendustakan (balasan) yang terbaik,', '', 'https://everyayah.com/data/Alafasy_128kbps/092009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:10', 92, 10, 30, 595, 6068, 'فَسَنُيَسِّرُهٗ لِلْعُسْرٰىۗ', 'Kami akan memudahkannya menuju jalan kesengsaraan.', '', 'https://everyayah.com/data/Alafasy_128kbps/092010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:11', 92, 11, 30, 595, 6069, 'وَمَا يُغْنِيْ عَنْهُ مَالُهٗٓ اِذَا تَرَدّٰىٓۙ', 'Hartanya tidak bermanfaat baginya apabila dia telah binasa.', '', 'https://everyayah.com/data/Alafasy_128kbps/092011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:12', 92, 12, 30, 595, 6070, 'اِنَّ عَلَيْنَا لَلْهُدٰىۖ', 'Sesungguhnya Kamilah yang (berhak) memberi petunjuk.', '', 'https://everyayah.com/data/Alafasy_128kbps/092012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:13', 92, 13, 30, 595, 6071, 'وَاِنَّ لَنَا لَلْاٰخِرَةَ وَالْاُوْلٰىۗ', 'Sesungguhnya milik Kamilah akhirat dan dunia.', '', 'https://everyayah.com/data/Alafasy_128kbps/092013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:14', 92, 14, 30, 595, 6072, 'فَاَنْذَرْتُكُمْ نَارًا تَلَظّٰىۚ', 'Aku memperingatkanmu dengan neraka yang menyala-nyala.', '', 'https://everyayah.com/data/Alafasy_128kbps/092014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:15', 92, 15, 30, 596, 6073, 'لَا يَصْلٰىهَآ اِلَّا الْاَشْقَىۙ', 'Tidak masuk ke dalamnya kecuali orang yang paling celaka,', '', 'https://everyayah.com/data/Alafasy_128kbps/092015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:16', 92, 16, 30, 596, 6074, 'الَّذِيْ كَذَّبَ وَتَوَلّٰىۗ', 'yang mendustakan (kebenaran) dan berpaling (dari keimanan).', '', 'https://everyayah.com/data/Alafasy_128kbps/092016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:17', 92, 17, 30, 596, 6075, 'وَسَيُجَنَّبُهَا الْاَتْقَىۙ', 'Akan dijauhkan darinya (neraka) orang yang paling bertakwa,', '', 'https://everyayah.com/data/Alafasy_128kbps/092017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:18', 92, 18, 30, 596, 6076, 'الَّذِيْ يُؤْتِيْ مَالَهٗ يَتَزَكّٰىۚ', 'yang menginfakkan hartanya (di jalan Allah) untuk membersihkan (diri dari sifat kikir dan tamak).', '', 'https://everyayah.com/data/Alafasy_128kbps/092018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:19', 92, 19, 30, 596, 6077, 'وَمَا لِاَحَدٍ عِنْدَهٗ مِنْ نِّعْمَةٍ تُجْزٰىٓۙ', 'Tidak ada suatu nikmat pun yang diberikan seseorang kepadanya yang harus dibalas,758)', '758) Maksudnya adalah bahwa orang-orang yang bertakwa membantu orang lain bukan karena orang itu berjasa kepadanya sehingga perlu membalasnya, melainkan hanya mengharap rida Allah.', 'https://everyayah.com/data/Alafasy_128kbps/092019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:20', 92, 20, 30, 596, 6078, 'اِلَّا ابْتِغَاۤءَ وَجْهِ رَبِّهِ الْاَعْلٰىۚ', 'kecuali (dia memberikannya semata-mata) karena mencari keridaan Tuhannya Yang Maha Tinggi.', '', 'https://everyayah.com/data/Alafasy_128kbps/092020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('92:21', 92, 21, 30, 596, 6079, 'وَلَسَوْفَ يَرْضٰى ࣖ', 'Sungguh, kelak dia akan mendapatkan kepuasan (menerima balasan amalnya).', '', 'https://everyayah.com/data/Alafasy_128kbps/092021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('93:1', 93, 1, 30, 596, 6080, 'وَالضُّحٰىۙ', 'Demi waktu duha', '', 'https://everyayah.com/data/Alafasy_128kbps/093001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('93:2', 93, 2, 30, 596, 6081, 'وَالَّيْلِ اِذَا سَجٰىۙ', 'dan demi waktu malam apabila telah sunyi,', '', 'https://everyayah.com/data/Alafasy_128kbps/093002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('93:3', 93, 3, 30, 596, 6082, 'مَا وَدَّعَكَ رَبُّكَ وَمَا قَلٰىۗ', 'Tuhanmu (Nabi Muhammad) tidak meninggalkan dan tidak (pula) membencimu.', '', 'https://everyayah.com/data/Alafasy_128kbps/093003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('93:4', 93, 4, 30, 596, 6083, 'وَلَلْاٰخِرَةُ خَيْرٌ لَّكَ مِنَ الْاُوْلٰىۗ', 'Sungguh, akhirat itu lebih baik bagimu daripada yang permulaan (dunia).', '', 'https://everyayah.com/data/Alafasy_128kbps/093004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('93:5', 93, 5, 30, 596, 6084, 'وَلَسَوْفَ يُعْطِيْكَ رَبُّكَ فَتَرْضٰىۗ', 'Sungguh, kelak (di akhirat nanti) Tuhanmu pasti memberikan karunia-Nya kepadamu sehingga engkau rida.', '', 'https://everyayah.com/data/Alafasy_128kbps/093005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('93:6', 93, 6, 30, 596, 6085, 'اَلَمْ يَجِدْكَ يَتِيْمًا فَاٰوٰىۖ', 'Bukankah Dia mendapatimu sebagai seorang yatim, lalu Dia melindungi(-mu);', '', 'https://everyayah.com/data/Alafasy_128kbps/093006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('93:7', 93, 7, 30, 596, 6086, 'وَوَجَدَكَ ضَاۤلًّا فَهَدٰىۖ', 'mendapatimu sebagai seorang yang tidak tahu (tentang syariat), lalu Dia memberimu petunjuk (wahyu);', '', 'https://everyayah.com/data/Alafasy_128kbps/093007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('93:8', 93, 8, 30, 596, 6087, 'وَوَجَدَكَ عَاۤىِٕلًا فَاَغْنٰىۗ', 'dan mendapatimu sebagai seorang yang fakir, lalu Dia memberimu kecukupan?', '', 'https://everyayah.com/data/Alafasy_128kbps/093008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('93:9', 93, 9, 30, 596, 6088, 'فَاَمَّا الْيَتِيْمَ فَلَا تَقْهَرْۗ', 'Terhadap anak yatim, janganlah engkau berlaku sewenang-wenang.', '', 'https://everyayah.com/data/Alafasy_128kbps/093009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('93:10', 93, 10, 30, 596, 6089, 'وَاَمَّا السَّاۤىِٕلَ فَلَا تَنْهَرْ', 'Terhadap orang yang meminta-minta, janganlah engkau menghardik.', '', 'https://everyayah.com/data/Alafasy_128kbps/093010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('93:11', 93, 11, 30, 596, 6090, 'وَاَمَّا بِنِعْمَةِ رَبِّكَ فَحَدِّثْ ࣖ', 'Terhadap nikmat Tuhanmu, nyatakanlah (dengan bersyukur).', '', 'https://everyayah.com/data/Alafasy_128kbps/093011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('94:1', 94, 1, 30, 596, 6091, 'اَلَمْ نَشْرَحْ لَكَ صَدْرَكَۙ', 'Bukankah Kami telah melapangkan dadamu (Nabi Muhammad),', '', 'https://everyayah.com/data/Alafasy_128kbps/094001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('94:2', 94, 2, 30, 596, 6092, 'وَوَضَعْنَا عَنْكَ وِزْرَكَۙ', 'meringankan beban (tugas-tugas kenabian) darimu', '', 'https://everyayah.com/data/Alafasy_128kbps/094002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('94:3', 94, 3, 30, 596, 6093, 'الَّذِيْٓ اَنْقَضَ ظَهْرَكَۙ', 'yang memberatkan punggungmu,', '', 'https://everyayah.com/data/Alafasy_128kbps/094003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('94:4', 94, 4, 30, 596, 6094, 'وَرَفَعْنَا لَكَ ذِكْرَكَۗ', 'dan meninggikan (derajat)-mu (dengan selalu) menyebut-nyebut (nama)-mu?', '', 'https://everyayah.com/data/Alafasy_128kbps/094004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('94:5', 94, 5, 30, 596, 6095, 'فَاِنَّ مَعَ الْعُسْرِ يُسْرًاۙ', 'Maka, sesungguhnya beserta kesulitan ada kemudahan.', '', 'https://everyayah.com/data/Alafasy_128kbps/094005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('94:6', 94, 6, 30, 596, 6096, 'اِنَّ مَعَ الْعُسْرِ يُسْرًاۗ', 'Sesungguhnya beserta kesulitan ada kemudahan.', '', 'https://everyayah.com/data/Alafasy_128kbps/094006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('94:7', 94, 7, 30, 596, 6097, 'فَاِذَا فَرَغْتَ فَانْصَبْۙ', 'Apabila engkau telah selesai (dengan suatu kebajikan), teruslah bekerja keras (untuk kebajikan yang lain)', '', 'https://everyayah.com/data/Alafasy_128kbps/094007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('94:8', 94, 8, 30, 596, 6098, 'وَاِلٰى رَبِّكَ فَارْغَبْ ࣖ', 'dan hanya kepada Tuhanmu berharaplah!', '', 'https://everyayah.com/data/Alafasy_128kbps/094008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('95:1', 95, 1, 30, 597, 6099, 'وَالتِّيْنِ وَالزَّيْتُوْنِۙ', 'Demi (buah) tin dan (buah) zaitun,', '', 'https://everyayah.com/data/Alafasy_128kbps/095001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('95:2', 95, 2, 30, 597, 6100, 'وَطُوْرِ سِيْنِيْنَۙ', 'demi gunung Sinai,', '', 'https://everyayah.com/data/Alafasy_128kbps/095002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('95:3', 95, 3, 30, 597, 6101, 'وَهٰذَا الْبَلَدِ الْاَمِيْنِۙ', 'dan demi negeri (Makkah) yang aman ini,', '', 'https://everyayah.com/data/Alafasy_128kbps/095003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('95:4', 95, 4, 30, 597, 6102, 'لَقَدْ خَلَقْنَا الْاِنْسَانَ فِيْٓ اَحْسَنِ تَقْوِيْمٍۖ', 'sungguh, Kami benar-benar telah menciptakan manusia dalam bentuk yang sebaik-baiknya.', '', 'https://everyayah.com/data/Alafasy_128kbps/095004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('95:5', 95, 5, 30, 597, 6103, 'ثُمَّ رَدَدْنٰهُ اَسْفَلَ سٰفِلِيْنَۙ', 'Kemudian, kami kembalikan dia ke tempat yang serendah-rendahnya,', '', 'https://everyayah.com/data/Alafasy_128kbps/095005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('95:6', 95, 6, 30, 597, 6104, 'اِلَّا الَّذِيْنَ اٰمَنُوْا وَعَمِلُوا الصّٰلِحٰتِ فَلَهُمْ اَجْرٌ غَيْرُ مَمْنُوْنٍۗ', 'kecuali orang-orang yang beriman dan mengerjakan kebajikan. Maka, mereka akan mendapat pahala yang tidak putus-putusnya.', '', 'https://everyayah.com/data/Alafasy_128kbps/095006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('95:7', 95, 7, 30, 597, 6105, 'فَمَا يُكَذِّبُكَ بَعْدُ بِالدِّيْنِۗ', 'Maka, apa alasanmu (wahai orang kafir) mendustakan hari Pembalasan setelah (adanya bukti-bukti) itu?', '', 'https://everyayah.com/data/Alafasy_128kbps/095007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('95:8', 95, 8, 30, 597, 6106, 'اَلَيْسَ اللّٰهُ بِاَحْكَمِ الْحٰكِمِيْنَ ࣖ', 'Bukankah Allah hakim yang paling adil?', '', 'https://everyayah.com/data/Alafasy_128kbps/095008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:1', 96, 1, 30, 597, 6107, 'اِقْرَأْ بِاسْمِ رَبِّكَ الَّذِيْ خَلَقَۚ', 'Bacalah dengan (menyebut) nama Tuhanmu yang menciptakan!', '', 'https://everyayah.com/data/Alafasy_128kbps/096001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:2', 96, 2, 30, 597, 6108, 'خَلَقَ الْاِنْسَانَ مِنْ عَلَقٍۚ', 'Dia menciptakan manusia dari segumpal darah.', '', 'https://everyayah.com/data/Alafasy_128kbps/096002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:3', 96, 3, 30, 597, 6109, 'اِقْرَأْ وَرَبُّكَ الْاَكْرَمُۙ', 'Bacalah! Tuhanmulah Yang Maha Mulia,', '', 'https://everyayah.com/data/Alafasy_128kbps/096003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:4', 96, 4, 30, 597, 6110, 'الَّذِيْ عَلَّمَ بِالْقَلَمِۙ', 'yang mengajar (manusia) dengan pena.', '', 'https://everyayah.com/data/Alafasy_128kbps/096004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:5', 96, 5, 30, 597, 6111, 'عَلَّمَ الْاِنْسَانَ مَا لَمْ يَعْلَمْۗ', 'Dia mengajarkan manusia apa yang tidak diketahuinya.', '', 'https://everyayah.com/data/Alafasy_128kbps/096005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:6', 96, 6, 30, 597, 6112, 'كَلَّآ اِنَّ الْاِنْسَانَ لَيَطْغٰىٓ ۙ', 'Sekali-kali tidak! Sesungguhnya manusia itu benar-benar melampaui batas', '', 'https://everyayah.com/data/Alafasy_128kbps/096006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:7', 96, 7, 30, 597, 6113, 'اَنْ رَّاٰهُ اسْتَغْنٰىۗ', 'ketika melihat dirinya serba berkecukupan.', '', 'https://everyayah.com/data/Alafasy_128kbps/096007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:8', 96, 8, 30, 597, 6114, 'اِنَّ اِلٰى رَبِّكَ الرُّجْعٰىۗ', 'Sesungguhnya hanya kepada Tuhanmulah tempat kembali(-mu).', '', 'https://everyayah.com/data/Alafasy_128kbps/096008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:9', 96, 9, 30, 597, 6115, 'اَرَاَيْتَ الَّذِيْ يَنْهٰىۙ', 'Tahukah kamu tentang orang yang melarang', '', 'https://everyayah.com/data/Alafasy_128kbps/096009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:10', 96, 10, 30, 597, 6116, 'عَبْدًا اِذَا صَلّٰىۗ', 'seorang hamba ketika dia melaksanakan salat?', '', 'https://everyayah.com/data/Alafasy_128kbps/096010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:11', 96, 11, 30, 597, 6117, 'اَرَاَيْتَ اِنْ كَانَ عَلَى الْهُدٰىٓۙ', 'Bagaimana pendapatmu kalau terbukti dia berada di dalam kebenaran', '', 'https://everyayah.com/data/Alafasy_128kbps/096011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:12', 96, 12, 30, 597, 6118, 'اَوْ اَمَرَ بِالتَّقْوٰىۗ', 'atau dia menyuruh bertakwa (kepada Allah)?', '', 'https://everyayah.com/data/Alafasy_128kbps/096012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:13', 96, 13, 30, 597, 6119, 'اَرَاَيْتَ اِنْ كَذَّبَ وَتَوَلّٰىۗ', 'Bagaimana pendapatmu kalau dia mendustakan (kebenaran) dan berpaling (dari keimanan)?', '', 'https://everyayah.com/data/Alafasy_128kbps/096013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:14', 96, 14, 30, 597, 6120, 'اَلَمْ يَعْلَمْ بِاَنَّ اللّٰهَ يَرٰىۗ', 'Tidakkah dia mengetahui bahwa sesungguhnya Allah melihat (segala perbuatannya)?', '', 'https://everyayah.com/data/Alafasy_128kbps/096014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:15', 96, 15, 30, 597, 6121, 'كَلَّا لَىِٕنْ لَّمْ يَنْتَهِ ەۙ لَنَسْفَعًاۢ بِالنَّاصِيَةِۙ', 'Sekali-kali tidak! Sungguh, jika dia tidak berhenti (berbuat demikian), niscaya Kami tarik ubun-ubunnya (ke dalam neraka),', '', 'https://everyayah.com/data/Alafasy_128kbps/096015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:16', 96, 16, 30, 597, 6122, 'نَاصِيَةٍ كَاذِبَةٍ خَاطِئَةٍۚ', '(yaitu) ubun-ubun orang yang mendustakan (kebenaran) dan durhaka.', '', 'https://everyayah.com/data/Alafasy_128kbps/096016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:17', 96, 17, 30, 597, 6123, 'فَلْيَدْعُ نَادِيَهٗۙ', 'Biarlah dia memanggil golongannya (untuk menolongnya).', '', 'https://everyayah.com/data/Alafasy_128kbps/096017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:18', 96, 18, 30, 597, 6124, 'سَنَدْعُ الزَّبَانِيَةَۙ', 'Kelak Kami akan memanggil (Malaikat) Zabaniah (penyiksa orang-orang yang berdosa).759)', '759) Zabaniah adalah malaikat yang bertugas menyiksa orang-orang yang berdosa.', 'https://everyayah.com/data/Alafasy_128kbps/096018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('96:19', 96, 19, 30, 597, 6125, 'كَلَّاۗ  لَا تُطِعْهُ وَاسْجُدْ وَاقْتَرِبْ ۩ ࣖ', 'Sekali-kali tidak! Janganlah patuh kepadanya, (tetapi) sujud dan mendekatlah (kepada Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/096019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('97:1', 97, 1, 30, 598, 6126, 'اِنَّآ اَنْزَلْنٰهُ فِيْ لَيْلَةِ الْقَدْرِ ', 'Sesungguhnya Kami telah menurunkannya (Al-Qur’an) pada Lailatulqadar.', '', 'https://everyayah.com/data/Alafasy_128kbps/097001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('97:2', 97, 2, 30, 598, 6127, 'وَمَآ اَدْرٰىكَ مَا لَيْلَةُ الْقَدْرِۗ', 'Tahukah kamu apakah Lailatulqadar itu?', '', 'https://everyayah.com/data/Alafasy_128kbps/097002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('97:3', 97, 3, 30, 598, 6128, 'لَيْلَةُ الْقَدْرِ ەۙ خَيْرٌ مِّنْ اَلْفِ شَهْرٍۗ', 'Lailatulqadar itu lebih baik daripada seribu bulan.', '', 'https://everyayah.com/data/Alafasy_128kbps/097003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('97:4', 97, 4, 30, 598, 6129, 'تَنَزَّلُ الْمَلٰۤىِٕكَةُ وَالرُّوْحُ فِيْهَا بِاِذْنِ رَبِّهِمْۚ مِنْ كُلِّ اَمْرٍۛ', 'Pada malam itu turun para malaikat dan Rūḥ (Jibril) dengan izin Tuhannya untuk mengatur semua urusan.', '', 'https://everyayah.com/data/Alafasy_128kbps/097004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('97:5', 97, 5, 30, 598, 6130, 'سَلٰمٌ ۛهِيَ حَتّٰى مَطْلَعِ الْفَجْرِ ࣖ', 'Sejahteralah (malam) itu sampai terbit fajar.', '', 'https://everyayah.com/data/Alafasy_128kbps/097005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('98:1', 98, 1, 30, 598, 6131, 'لَمْ يَكُنِ الَّذِيْنَ كَفَرُوْا مِنْ اَهْلِ الْكِتٰبِ وَالْمُشْرِكِيْنَ مُنْفَكِّيْنَ حَتّٰى تَأْتِيَهُمُ الْبَيِّنَةُۙ', 'Orang-orang yang kufur dari golongan Ahlulkitab dan orang-orang musyrik tidak akan meninggalkan (kekufuran mereka) sampai datang kepada mereka bukti yang nyata,', '', 'https://everyayah.com/data/Alafasy_128kbps/098001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('98:2', 98, 2, 30, 598, 6132, 'رَسُوْلٌ مِّنَ اللّٰهِ يَتْلُوْا صُحُفًا مُّطَهَّرَةًۙ', '(yaitu) seorang Rasul dari Allah (Nabi Muhammad) yang membacakan lembaran-lembaran suci (Al-Qur’an)', '', 'https://everyayah.com/data/Alafasy_128kbps/098002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('98:3', 98, 3, 30, 598, 6133, 'فِيْهَا كُتُبٌ قَيِّمَةٌ  ۗ', 'yang di dalamnya terdapat (isi) kitab-kitab yang lurus (benar).', '', 'https://everyayah.com/data/Alafasy_128kbps/098003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('98:4', 98, 4, 30, 598, 6134, 'وَمَا تَفَرَّقَ الَّذِيْنَ اُوْتُوا الْكِتٰبَ اِلَّا مِنْۢ بَعْدِ مَا جَاۤءَتْهُمُ الْبَيِّنَةُ ۗ', 'Tidaklah terpecah-belah orang-orang Ahlulkitab, melainkan setelah datang kepada mereka bukti yang nyata. ', '', 'https://everyayah.com/data/Alafasy_128kbps/098004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('98:5', 98, 5, 30, 598, 6135, 'وَمَآ اُمِرُوْٓا اِلَّا لِيَعْبُدُوا اللّٰهَ مُخْلِصِيْنَ لَهُ الدِّيْنَ ەۙ حُنَفَاۤءَ وَيُقِيْمُوا الصَّلٰوةَ وَيُؤْتُوا الزَّكٰوةَ وَذٰلِكَ دِيْنُ الْقَيِّمَةِۗ', 'Mereka tidak diperintah, kecuali untuk menyembah Allah dengan mengikhlaskan ketaatan kepada-Nya lagi hanif (istikamah), melaksanakan salat, dan menunaikan zakat. Itulah agama yang lurus (benar).', '', 'https://everyayah.com/data/Alafasy_128kbps/098005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('98:6', 98, 6, 30, 598, 6136, 'اِنَّ الَّذِيْنَ كَفَرُوْا مِنْ اَهْلِ الْكِتٰبِ وَالْمُشْرِكِيْنَ فِيْ نَارِ جَهَنَّمَ خٰلِدِيْنَ فِيْهَاۗ اُولٰۤىِٕكَ هُمْ شَرُّ الْبَرِيَّةِۗ', 'Sesungguhnya orang-orang yang kufur dari golongan Ahlulkitab dan orang-orang musyrik (akan masuk) neraka Jahanam. Mereka kekal di dalamnya. Mereka itulah seburuk-buruk makhluk.', '', 'https://everyayah.com/data/Alafasy_128kbps/098006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('98:7', 98, 7, 30, 598, 6137, 'اِنَّ الَّذِيْنَ اٰمَنُوْا وَعَمِلُوا الصّٰلِحٰتِ اُولٰۤىِٕكَ هُمْ خَيْرُ الْبَرِيَّةِۗ', 'Sesungguhnya orang-orang yang beriman dan mengerjakan kebajikan, mereka itulah sebaik-baik makhluk.', '', 'https://everyayah.com/data/Alafasy_128kbps/098007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('98:8', 98, 8, 30, 599, 6138, 'جَزَاۤؤُهُمْ عِنْدَ رَبِّهِمْ جَنّٰتُ عَدْنٍ تَجْرِيْ مِنْ تَحْتِهَا الْاَنْهٰرُ خٰلِدِيْنَ فِيْهَآ اَبَدًا ۗرَضِيَ اللّٰهُ عَنْهُمْ وَرَضُوْا عَنْهُ ۗ ذٰلِكَ لِمَنْ خَشِيَ رَبَّهٗ ࣖ', 'Balasan mereka di sisi Tuhannya adalah surga ‘Adn yang mengalir di bawahnya sungai-sungai. Mereka kekal di dalamnya selama-lamanya. Allah rida terhadap mereka dan mereka pun rida kepada-Nya. Itu adalah (balasan) bagi orang yang takut kepada Tuhannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/098008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('99:1', 99, 1, 30, 599, 6139, 'اِذَا زُلْزِلَتِ الْاَرْضُ زِلْزَالَهَاۙ', 'Apabila bumi diguncangkan dengan guncangan yang dahsyat,', '', 'https://everyayah.com/data/Alafasy_128kbps/099001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('99:2', 99, 2, 30, 599, 6140, 'وَاَخْرَجَتِ الْاَرْضُ اَثْقَالَهَاۙ', 'bumi mengeluarkan isi perutnya,', '', 'https://everyayah.com/data/Alafasy_128kbps/099002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('99:3', 99, 3, 30, 599, 6141, 'وَقَالَ الْاِنْسَانُ مَا لَهَاۚ', 'dan manusia bertanya, “Apa yang terjadi dengannya (bumi)?”', '', 'https://everyayah.com/data/Alafasy_128kbps/099003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('99:4', 99, 4, 30, 599, 6142, 'يَوْمَىِٕذٍ تُحَدِّثُ اَخْبَارَهَاۙ', 'Pada hari itu (bumi) menyampaikan berita (tentang apa yang diperbuat manusia di atasnya)', '', 'https://everyayah.com/data/Alafasy_128kbps/099004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('99:5', 99, 5, 30, 599, 6143, 'بِاَنَّ رَبَّكَ اَوْحٰى لَهَاۗ', 'karena sesungguhnya Tuhanmu telah memerintahkan (yang demikian itu) kepadanya.', '', 'https://everyayah.com/data/Alafasy_128kbps/099005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('99:6', 99, 6, 30, 599, 6144, 'يَوْمَىِٕذٍ يَّصْدُرُ النَّاسُ اَشْتَاتًا ەۙ لِّيُرَوْا اَعْمَالَهُمْۗ', 'Pada hari itu manusia keluar (dari kuburnya) dalam keadaan terpencar untuk diperlihatkan kepada mereka (balasan) semua perbuatan mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/099006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('99:7', 99, 7, 30, 599, 6145, 'فَمَنْ يَّعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَّرَهٗۚ', 'Siapa yang mengerjakan kebaikan seberat zarah, dia akan melihat (balasan)-nya.', '', 'https://everyayah.com/data/Alafasy_128kbps/099007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('99:8', 99, 8, 30, 599, 6146, 'وَمَنْ يَّعْمَلْ مِثْقَالَ ذَرَّةٍ شَرًّا يَّرَهٗ ࣖ', 'Siapa yang mengerjakan kejahatan seberat zarah, dia akan melihat (balasan)-nya.', '', 'https://everyayah.com/data/Alafasy_128kbps/099008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('100:1', 100, 1, 30, 599, 6147, 'وَالْعٰدِيٰتِ ضَبْحًاۙ ', 'Demi kuda-kuda perang yang berlari kencang terengah-engah,', '', 'https://everyayah.com/data/Alafasy_128kbps/100001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('100:2', 100, 2, 30, 599, 6148, 'فَالْمُوْرِيٰتِ قَدْحًاۙ', 'yang memercikkan bunga api (dengan entakan kakinya),', '', 'https://everyayah.com/data/Alafasy_128kbps/100002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('100:3', 100, 3, 30, 599, 6149, 'فَالْمُغِيْرٰتِ صُبْحًاۙ', 'yang menyerang (dengan tiba-tiba) pada waktu pagi', '', 'https://everyayah.com/data/Alafasy_128kbps/100003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('100:4', 100, 4, 30, 599, 6150, 'فَاَثَرْنَ بِهٖ نَقْعًاۙ', 'sehingga menerbangkan debu,', '', 'https://everyayah.com/data/Alafasy_128kbps/100004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('100:5', 100, 5, 30, 599, 6151, 'فَوَسَطْنَ بِهٖ جَمْعًاۙ', 'lalu menyerbu ke tengah-tengah kumpulan musuh,', '', 'https://everyayah.com/data/Alafasy_128kbps/100005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('100:6', 100, 6, 30, 599, 6152, 'اِنَّ الْاِنْسَانَ لِرَبِّهٖ لَكَنُوْدٌ ۚ', 'sesungguhnya manusia itu sangatlah ingkar kepada Tuhannya. ', '', 'https://everyayah.com/data/Alafasy_128kbps/100006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('100:7', 100, 7, 30, 599, 6153, 'وَاِنَّهٗ عَلٰى ذٰلِكَ لَشَهِيْدٌۚ', 'Sesungguhnya dia benar-benar menjadi saksi atas hal itu (keingkarannya).', '', 'https://everyayah.com/data/Alafasy_128kbps/100007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('100:8', 100, 8, 30, 599, 6154, 'وَاِنَّهٗ لِحُبِّ الْخَيْرِ لَشَدِيْدٌ ۗ', 'Sesungguhnya cintanya pada harta benar-benar berlebihan.', '', 'https://everyayah.com/data/Alafasy_128kbps/100008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('100:9', 100, 9, 30, 599, 6155, '۞ اَفَلَا يَعْلَمُ اِذَا بُعْثِرَ مَا فِى الْقُبُوْرِۙ', 'Maka, tidakkah dia mengetahui (apa yang akan dialaminya) apabila dikeluarkan apa yang ada di dalam kubur', '', 'https://everyayah.com/data/Alafasy_128kbps/100009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('100:10', 100, 10, 30, 600, 6156, 'وَحُصِّلَ مَا فِى الصُّدُوْرِۙ', 'dan ditampakkan apa yang tersimpan di dalam dada?', '', 'https://everyayah.com/data/Alafasy_128kbps/100010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('100:11', 100, 11, 30, 600, 6157, 'اِنَّ رَبَّهُمْ بِهِمْ يَوْمَىِٕذٍ لَّخَبِيْرٌ ࣖ', 'Sesungguhnya Tuhan mereka pada hari itu benar-benar Maha Teliti terhadap (keadaan) mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/100011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('101:1', 101, 1, 30, 600, 6158, 'اَلْقَارِعَةُۙ', 'Al-Qāri‘ah (hari Kiamat yang menggetarkan).', '', 'https://everyayah.com/data/Alafasy_128kbps/101001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('101:2', 101, 2, 30, 600, 6159, 'مَا الْقَارِعَةُ ۚ', 'Apakah al-Qāri‘ah itu?', '', 'https://everyayah.com/data/Alafasy_128kbps/101002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('101:3', 101, 3, 30, 600, 6160, 'وَمَآ اَدْرٰىكَ مَا الْقَارِعَةُ ۗ', 'Tahukah kamu apakah al-Qāri‘ah itu?', '', 'https://everyayah.com/data/Alafasy_128kbps/101003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('101:4', 101, 4, 30, 600, 6161, 'يَوْمَ يَكُوْنُ النَّاسُ كَالْفَرَاشِ الْمَبْثُوْثِۙ', 'Pada hari itu manusia seperti laron yang beterbangan', '', 'https://everyayah.com/data/Alafasy_128kbps/101004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('101:5', 101, 5, 30, 600, 6162, 'وَتَكُوْنُ الْجِبَالُ كَالْعِهْنِ الْمَنْفُوْشِۗ', 'dan gunung-gunung seperti bulu yang berhamburan.', '', 'https://everyayah.com/data/Alafasy_128kbps/101005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('101:6', 101, 6, 30, 600, 6163, 'فَاَمَّا مَنْ ثَقُلَتْ مَوَازِيْنُهٗۙ ', 'Siapa yang berat timbangan (kebaikan)-nya,', '', 'https://everyayah.com/data/Alafasy_128kbps/101006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('101:7', 101, 7, 30, 600, 6164, 'فَهُوَ فِيْ عِيْشَةٍ رَّاضِيَةٍۗ', 'dia berada dalam kehidupan yang menyenangkan.', '', 'https://everyayah.com/data/Alafasy_128kbps/101007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('101:8', 101, 8, 30, 600, 6165, 'وَاَمَّا مَنْ خَفَّتْ مَوَازِيْنُهٗۙ', 'Adapun orang yang ringan timbangan (kebaikan)-nya,', '', 'https://everyayah.com/data/Alafasy_128kbps/101008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('101:9', 101, 9, 30, 600, 6166, 'فَاُمُّهٗ هَاوِيَةٌ  ۗ', 'tempat kembalinya adalah (neraka) Hawiyah.', '', 'https://everyayah.com/data/Alafasy_128kbps/101009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('101:10', 101, 10, 30, 600, 6167, 'وَمَآ اَدْرٰىكَ مَا هِيَهْۗ', 'Tahukah kamu apakah (neraka Hawiyah) itu?', '', 'https://everyayah.com/data/Alafasy_128kbps/101010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('101:11', 101, 11, 30, 600, 6168, 'نَارٌ حَامِيَةٌ ࣖ', '(Ia adalah) api yang sangat panas.', '', 'https://everyayah.com/data/Alafasy_128kbps/101011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('102:1', 102, 1, 30, 600, 6169, 'اَلْهٰىكُمُ التَّكَاثُرُۙ', 'Berbangga-bangga dalam memperbanyak (dunia) telah melalaikanmu760)', '760) Maksudnya adalah bersaing memperbanyak anak, harta, pengikut, kemuliaan, dan sebagainya telah melalaikan manusia dari ketaatan kepada Allah Swt.', 'https://everyayah.com/data/Alafasy_128kbps/102001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('102:2', 102, 2, 30, 600, 6170, 'حَتّٰى زُرْتُمُ الْمَقَابِرَۗ', 'sampai kamu masuk ke dalam kubur.', '', 'https://everyayah.com/data/Alafasy_128kbps/102002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('102:3', 102, 3, 30, 600, 6171, 'كَلَّا سَوْفَ تَعْلَمُوْنَۙ', 'Sekali-kali tidak! Kelak kamu akan mengetahui (akibat perbuatanmu itu).', '', 'https://everyayah.com/data/Alafasy_128kbps/102003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('102:4', 102, 4, 30, 600, 6172, 'ثُمَّ كَلَّا سَوْفَ تَعْلَمُوْنَ ', 'Sekali-kali tidak (jangan melakukan itu)! Kelak kamu akan mengetahui (akibatnya).', '', 'https://everyayah.com/data/Alafasy_128kbps/102004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('102:5', 102, 5, 30, 600, 6173, 'كَلَّا لَوْ تَعْلَمُوْنَ عِلْمَ الْيَقِيْنِۗ', 'Sekali-kali tidak (jangan melakukan itu)! Sekiranya kamu mengetahui dengan pasti, (niscaya kamu tidak akan melakukannya).', '', 'https://everyayah.com/data/Alafasy_128kbps/102005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('102:6', 102, 6, 30, 600, 6174, 'لَتَرَوُنَّ الْجَحِيْمَۙ', 'Pasti kamu benar-benar akan melihat (neraka) Jahim.', '', 'https://everyayah.com/data/Alafasy_128kbps/102006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('102:7', 102, 7, 30, 600, 6175, 'ثُمَّ لَتَرَوُنَّهَا عَيْنَ الْيَقِيْنِۙ', 'Kemudian, kamu pasti benar-benar akan melihatnya dengan ainulyakin.', '', 'https://everyayah.com/data/Alafasy_128kbps/102007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('102:8', 102, 8, 30, 600, 6176, 'ثُمَّ لَتُسْـَٔلُنَّ يَوْمَىِٕذٍ عَنِ النَّعِيْمِ ࣖ', 'Kemudian, kamu pasti benar-benar akan ditanya pada hari itu tentang kenikmatan (yang megah di dunia itu).', '', 'https://everyayah.com/data/Alafasy_128kbps/102008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('103:1', 103, 1, 30, 601, 6177, 'وَالْعَصْرِۙ', 'Demi masa,', '', 'https://everyayah.com/data/Alafasy_128kbps/103001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('103:2', 103, 2, 30, 601, 6178, 'اِنَّ الْاِنْسَانَ لَفِيْ خُسْرٍۙ', 'sesungguhnya manusia benar-benar berada dalam kerugian,', '', 'https://everyayah.com/data/Alafasy_128kbps/103002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('103:3', 103, 3, 30, 601, 6179, 'اِلَّا الَّذِيْنَ اٰمَنُوْا وَعَمِلُوا الصّٰلِحٰتِ وَتَوَاصَوْا بِالْحَقِّ ەۙ وَتَوَاصَوْا بِالصَّبْرِ ࣖ', 'kecuali orang-orang yang beriman dan beramal saleh serta saling menasihati untuk kebenaran dan kesabaran.', '', 'https://everyayah.com/data/Alafasy_128kbps/103003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('104:1', 104, 1, 30, 601, 6180, 'وَيْلٌ لِّكُلِّ هُمَزَةٍ لُّمَزَةٍۙ', 'Celakalah setiap pengumpat lagi pencela', '', 'https://everyayah.com/data/Alafasy_128kbps/104001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('104:2', 104, 2, 30, 601, 6181, ' ۨالَّذِيْ جَمَعَ مَالًا وَّعَدَّدَهٗۙ', 'yang mengumpulkan harta dan menghitung-hitungnya.', '', 'https://everyayah.com/data/Alafasy_128kbps/104002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('104:3', 104, 3, 30, 601, 6182, 'يَحْسَبُ اَنَّ مَالَهٗٓ اَخْلَدَهٗۚ', 'Dia (manusia) mengira bahwa hartanya dapat mengekalkannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/104003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('104:4', 104, 4, 30, 601, 6183, 'كَلَّا لَيُنْۢبَذَنَّ فِى الْحُطَمَةِۖ', 'Sekali-kali tidak! Pasti dia akan dilemparkan ke dalam (neraka) Hutamah.', '', 'https://everyayah.com/data/Alafasy_128kbps/104004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('104:5', 104, 5, 30, 601, 6184, 'وَمَآ اَدْرٰىكَ مَا الْحُطَمَةُ ۗ', 'Tahukah kamu apakah (neraka) Hutamah?', '', 'https://everyayah.com/data/Alafasy_128kbps/104005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('104:6', 104, 6, 30, 601, 6185, 'نَارُ اللّٰهِ الْمُوْقَدَةُۙ', '(Ia adalah) api (azab) Allah yang dinyalakan', '', 'https://everyayah.com/data/Alafasy_128kbps/104006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('104:7', 104, 7, 30, 601, 6186, 'الَّتِيْ تَطَّلِعُ عَلَى الْاَفْـِٕدَةِۗ', 'yang (membakar) naik sampai ke hati.', '', 'https://everyayah.com/data/Alafasy_128kbps/104007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('104:8', 104, 8, 30, 601, 6187, 'اِنَّهَا عَلَيْهِمْ مُّؤْصَدَةٌۙ', 'Sesungguhnya dia (api itu) tertutup rapat (sebagai hukuman) atas mereka,', '', 'https://everyayah.com/data/Alafasy_128kbps/104008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('104:9', 104, 9, 30, 601, 6188, 'فِيْ عَمَدٍ مُّمَدَّدَةٍ ࣖ', '(sedangkan mereka) diikat pada tiang-tiang yang panjang.', '', 'https://everyayah.com/data/Alafasy_128kbps/104009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('105:1', 105, 1, 30, 601, 6189, 'اَلَمْ تَرَ كَيْفَ فَعَلَ رَبُّكَ بِاَصْحٰبِ الْفِيْلِۗ', 'Tidakkah engkau (Nabi Muhammad) memperhatikan bagaimana Tuhanmu telah bertindak terhadap pasukan bergajah?', '', 'https://everyayah.com/data/Alafasy_128kbps/105001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('105:2', 105, 2, 30, 601, 6190, 'اَلَمْ يَجْعَلْ كَيْدَهُمْ فِيْ تَضْلِيْلٍۙ', 'Bukankah Dia telah menjadikan tipu daya mereka itu sia-sia?', '', 'https://everyayah.com/data/Alafasy_128kbps/105002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('105:3', 105, 3, 30, 601, 6191, 'وَّاَرْسَلَ عَلَيْهِمْ طَيْرًا اَبَابِيْلَۙ', 'Dia mengirimkan kepada mereka burung yang berbondong-bondong', '', 'https://everyayah.com/data/Alafasy_128kbps/105003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('105:4', 105, 4, 30, 601, 6192, 'تَرْمِيْهِمْ بِحِجَارَةٍ مِّنْ سِجِّيْلٍۙ', 'yang melempari mereka dengan batu dari tanah liat yang dibakar,', '', 'https://everyayah.com/data/Alafasy_128kbps/105004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('105:5', 105, 5, 30, 601, 6193, 'فَجَعَلَهُمْ كَعَصْفٍ مَّأْكُوْلٍ ࣖ ', 'sehingga Dia menjadikan mereka seperti daun-daun yang dimakan (ulat).', '', 'https://everyayah.com/data/Alafasy_128kbps/105005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('106:1', 106, 1, 30, 602, 6194, 'لِاِيْلٰفِ قُرَيْشٍۙ', 'Disebabkan oleh kebiasaan orang-orang Quraisy,', '', 'https://everyayah.com/data/Alafasy_128kbps/106001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('106:2', 106, 2, 30, 602, 6195, 'اٖلٰفِهِمْ رِحْلَةَ الشِّتَاۤءِ وَالصَّيْفِۚ', '(yaitu) kebiasaan mereka bepergian pada musim dingin dan musim panas (sehingga mendapatkan banyak keuntungan),', '', 'https://everyayah.com/data/Alafasy_128kbps/106002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('106:3', 106, 3, 30, 602, 6196, 'فَلْيَعْبُدُوْا رَبَّ هٰذَا الْبَيْتِۙ', 'maka hendaklah mereka menyembah Tuhan (pemilik) rumah ini (Ka‘bah)', '', 'https://everyayah.com/data/Alafasy_128kbps/106003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('106:4', 106, 4, 30, 602, 6197, 'الَّذِيْٓ اَطْعَمَهُمْ مِّنْ جُوْعٍ ەۙ وَّاٰمَنَهُمْ مِّنْ خَوْفٍ ࣖ', 'yang telah memberi mereka makanan untuk menghilangkan lapar dan mengamankan mereka dari rasa takut.', '', 'https://everyayah.com/data/Alafasy_128kbps/106004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('107:1', 107, 1, 30, 602, 6198, 'اَرَءَيْتَ الَّذِيْ يُكَذِّبُ بِالدِّيْنِۗ', 'Tahukah kamu (orang) yang mendustakan agama?', '', 'https://everyayah.com/data/Alafasy_128kbps/107001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('107:2', 107, 2, 30, 602, 6199, 'فَذٰلِكَ الَّذِيْ يَدُعُّ الْيَتِيْمَۙ', 'Itulah orang yang menghardik anak yatim', '', 'https://everyayah.com/data/Alafasy_128kbps/107002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('107:3', 107, 3, 30, 602, 6200, 'وَلَا يَحُضُّ عَلٰى طَعَامِ الْمِسْكِيْنِۗ', 'dan tidak menganjurkan untuk memberi makan orang miskin.', '', 'https://everyayah.com/data/Alafasy_128kbps/107003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('107:4', 107, 4, 30, 602, 6201, 'فَوَيْلٌ لِّلْمُصَلِّيْنَۙ', 'Celakalah orang-orang yang melaksanakan salat,', '', 'https://everyayah.com/data/Alafasy_128kbps/107004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('107:5', 107, 5, 30, 602, 6202, 'الَّذِيْنَ هُمْ عَنْ صَلَاتِهِمْ سَاهُوْنَۙ', '(yaitu) yang lalai terhadap salatnya,761)', '761) Melalaikan salat mencakup lalai akan waktu dan tujuan salat serta bermalasan dalam mengerjakannya.', 'https://everyayah.com/data/Alafasy_128kbps/107005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('107:6', 107, 6, 30, 602, 6203, 'الَّذِيْنَ هُمْ يُرَاۤءُوْنَۙ', 'yang berbuat riya,762)', '762) Riya adalah melakukan sesuatu perbuatan tidak untuk mencari keridaan Allah, tetapi untuk mencari pujian atau kemasyhuran di masyarakat.', 'https://everyayah.com/data/Alafasy_128kbps/107006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('107:7', 107, 7, 30, 602, 6204, 'وَيَمْنَعُوْنَ الْمَاعُوْنَ ࣖ', 'dan enggan (memberi) bantuan.', '', 'https://everyayah.com/data/Alafasy_128kbps/107007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('108:1', 108, 1, 30, 602, 6205, 'اِنَّآ اَعْطَيْنٰكَ الْكَوْثَرَۗ', 'Sesungguhnya Kami telah memberimu (Nabi Muhammad) nikmat yang banyak.', '', 'https://everyayah.com/data/Alafasy_128kbps/108001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('108:2', 108, 2, 30, 602, 6206, 'فَصَلِّ لِرَبِّكَ وَانْحَرْۗ', 'Maka, laksanakanlah salat karena Tuhanmu dan berkurbanlah!', '', 'https://everyayah.com/data/Alafasy_128kbps/108002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('108:3', 108, 3, 30, 602, 6207, 'اِنَّ شَانِئَكَ هُوَ الْاَبْتَرُ ࣖ', 'Sesungguhnya orang yang membencimu, dialah yang terputus (dari rahmat Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/108003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('109:1', 109, 1, 30, 603, 6208, 'قُلْ يٰٓاَيُّهَا الْكٰفِرُوْنَۙ', 'Katakanlah (Nabi Muhammad), “Wahai orang-orang kafir,', '', 'https://everyayah.com/data/Alafasy_128kbps/109001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('109:2', 109, 2, 30, 603, 6209, 'لَآ اَعْبُدُ مَا تَعْبُدُوْنَۙ', 'aku tidak akan menyembah apa yang kamu sembah.', '', 'https://everyayah.com/data/Alafasy_128kbps/109002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('109:3', 109, 3, 30, 603, 6210, 'وَلَآ اَنْتُمْ عٰبِدُوْنَ مَآ اَعْبُدُۚ', 'Kamu juga bukan penyembah apa yang aku sembah.', '', 'https://everyayah.com/data/Alafasy_128kbps/109003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('109:4', 109, 4, 30, 603, 6211, 'وَلَآ اَنَا۠ عَابِدٌ مَّا عَبَدْتُّمْۙ', 'Aku juga tidak pernah menjadi penyembah apa yang kamu sembah.', '', 'https://everyayah.com/data/Alafasy_128kbps/109004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('109:5', 109, 5, 30, 603, 6212, 'وَلَآ اَنْتُمْ عٰبِدُوْنَ مَآ اَعْبُدُۗ', 'Kamu tidak pernah (pula) menjadi penyembah apa yang aku sembah.', '', 'https://everyayah.com/data/Alafasy_128kbps/109005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('109:6', 109, 6, 30, 603, 6213, 'لَكُمْ دِيْنُكُمْ وَلِيَ دِيْنِ ࣖ', 'Untukmu agamamu dan untukku agamaku.”', '', 'https://everyayah.com/data/Alafasy_128kbps/109006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('110:1', 110, 1, 30, 603, 6214, 'اِذَا جَاۤءَ نَصْرُ اللّٰهِ وَالْفَتْحُۙ', 'Apabila telah datang pertolongan Allah dan kemenangan', '', 'https://everyayah.com/data/Alafasy_128kbps/110001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('110:2', 110, 2, 30, 603, 6215, 'وَرَاَيْتَ النَّاسَ يَدْخُلُوْنَ فِيْ دِيْنِ اللّٰهِ اَفْوَاجًاۙ', 'dan engkau melihat manusia berbondong-bondong masuk agama Allah,', '', 'https://everyayah.com/data/Alafasy_128kbps/110002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('110:3', 110, 3, 30, 603, 6216, 'فَسَبِّحْ بِحَمْدِ رَبِّكَ وَاسْتَغْفِرْهُۗ اِنَّهٗ كَانَ تَوَّابًا ࣖ', 'bertasbihlah dengan memuji Tuhanmu dan mohonlah ampun kepada-Nya. Sesungguhnya Dia Maha Penerima tobat.', '', 'https://everyayah.com/data/Alafasy_128kbps/110003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('111:1', 111, 1, 30, 603, 6217, 'تَبَّتْ يَدَآ اَبِيْ لَهَبٍ وَّتَبَّۗ', 'Binasalah kedua tangan Abu Lahab dan benar-benar binasa dia.763)', '763) Yang dimaksud dengan kedua tangan Abu Lahab adalah Abu Lahab itu sendiri.', 'https://everyayah.com/data/Alafasy_128kbps/111001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('111:2', 111, 2, 30, 603, 6218, 'مَآ اَغْنٰى عَنْهُ مَالُهٗ وَمَا كَسَبَۗ', 'Tidaklah berguna baginya hartanya dan apa yang dia usahakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/111002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('111:3', 111, 3, 30, 603, 6219, 'سَيَصْلٰى نَارًا ذَاتَ لَهَبٍۙ', 'Kelak dia akan memasuki api yang bergejolak (neraka),', '', 'https://everyayah.com/data/Alafasy_128kbps/111003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('111:4', 111, 4, 30, 603, 6220, 'وَّامْرَاَتُهٗ ۗحَمَّالَةَ الْحَطَبِۚ', '(begitu pula) istrinya, pembawa kayu bakar (penyebar fitnah). ', '', 'https://everyayah.com/data/Alafasy_128kbps/111004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('111:5', 111, 5, 30, 603, 6221, 'فِيْ جِيْدِهَا حَبْلٌ مِّنْ مَّسَدٍ ࣖ', 'Di lehernya ada tali dari sabut yang dipintal.', '', 'https://everyayah.com/data/Alafasy_128kbps/111005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('112:1', 112, 1, 30, 604, 6222, 'قُلْ هُوَ اللّٰهُ اَحَدٌۚ', 'Katakanlah (Nabi Muhammad), “Dialah Allah Yang Maha Esa.', '', 'https://everyayah.com/data/Alafasy_128kbps/112001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('112:2', 112, 2, 30, 604, 6223, 'اَللّٰهُ الصَّمَدُۚ', 'Allah tempat meminta segala sesuatu.', '', 'https://everyayah.com/data/Alafasy_128kbps/112002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('112:3', 112, 3, 30, 604, 6224, 'لَمْ يَلِدْ وَلَمْ يُوْلَدْۙ', 'Dia tidak beranak dan tidak pula diperanakkan', '', 'https://everyayah.com/data/Alafasy_128kbps/112003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('112:4', 112, 4, 30, 604, 6225, 'وَلَمْ يَكُنْ لَّهٗ كُفُوًا اَحَدٌ ࣖ', 'serta tidak ada sesuatu pun yang setara dengan-Nya.”', '', 'https://everyayah.com/data/Alafasy_128kbps/112004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('113:1', 113, 1, 30, 604, 6226, 'قُلْ اَعُوْذُ بِرَبِّ الْفَلَقِۙ', 'Katakanlah (Nabi Muhammad), “Aku berlindung kepada Tuhan yang (menjaga) fajar (subuh) ', '', 'https://everyayah.com/data/Alafasy_128kbps/113001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('113:2', 113, 2, 30, 604, 6227, 'مِنْ شَرِّ مَا خَلَقَۙ', 'dari kejahatan (makhluk yang) Dia ciptakan,', '', 'https://everyayah.com/data/Alafasy_128kbps/113002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('113:3', 113, 3, 30, 604, 6228, 'وَمِنْ شَرِّ غَاسِقٍ اِذَا وَقَبَۙ', 'dari kejahatan malam apabila telah gelap gulita,', '', 'https://everyayah.com/data/Alafasy_128kbps/113003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('113:4', 113, 4, 30, 604, 6229, 'وَمِنْ شَرِّ النَّفّٰثٰتِ فِى الْعُقَدِۙ', 'dari kejahatan perempuan-perempuan (penyihir) yang meniup pada buhul-buhul (talinya),', '', 'https://everyayah.com/data/Alafasy_128kbps/113004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('113:5', 113, 5, 30, 604, 6230, 'وَمِنْ شَرِّ حَاسِدٍ اِذَا حَسَدَ ࣖ', 'dan dari kejahatan orang yang dengki apabila dia dengki.”', '', 'https://everyayah.com/data/Alafasy_128kbps/113005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('114:1', 114, 1, 30, 604, 6231, 'قُلْ اَعُوْذُ بِرَبِّ النَّاسِۙ', 'Katakanlah (Nabi Muhammad), “Aku berlindung kepada Tuhan manusia,', '', 'https://everyayah.com/data/Alafasy_128kbps/114001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('114:2', 114, 2, 30, 604, 6232, 'مَلِكِ النَّاسِۙ', 'raja manusia,', '', 'https://everyayah.com/data/Alafasy_128kbps/114002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('114:3', 114, 3, 30, 604, 6233, 'اِلٰهِ النَّاسِۙ', 'sembahan manusia', '', 'https://everyayah.com/data/Alafasy_128kbps/114003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('114:4', 114, 4, 30, 604, 6234, 'مِنْ شَرِّ الْوَسْوَاسِ ەۙ الْخَنَّاسِۖ', 'dari kejahatan (setan) pembisik yang bersembunyi', '', 'https://everyayah.com/data/Alafasy_128kbps/114004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('114:5', 114, 5, 30, 604, 6235, 'الَّذِيْ يُوَسْوِسُ فِيْ صُدُوْرِ النَّاسِۙ', 'yang membisikkan (kejahatan) ke dalam dada manusia,', '', 'https://everyayah.com/data/Alafasy_128kbps/114005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('114:6', 114, 6, 30, 604, 6236, 'مِنَ الْجِنَّةِ وَالنَّاسِ ࣖ ', 'dari (golongan) jin dan manusia.”', '', 'https://everyayah.com/data/Alafasy_128kbps/114006.mp3');
PRAGMA foreign_keys = ON;
